external_knowledge:
- "top movies" refers to the top 3 movies for each critic based on the number of views and likes; 
- "top critics" are determined by their average rating in descending order and total reviews in descending order;
- the results are limited to the top 10 critics.

sql:
SELECT critic_name
FROM critics
WHERE total_reviews > 100;

SELECT critic_name, total_reviews
FROM critics
ORDER BY total_reviews DESC;

SELECT movie_title
FROM movies
ORDER BY movie_title ASC;

SELECT critic_name, total_reviews
FROM critics
ORDER BY total_reviews DESC;

